import React from "react";
import { useSessionContext } from "../../contexts/SessionContext";
import "./NavigationBar.css";

function NavigationBar() {
  const {loggedIn, setLoggedOut} = useSessionContext();

  const logoutBtn = () => {
    setLoggedOut();
    this.history.push('/');
  }

  return (
    loggedIn ?
    <>
      <section className="header">
        <a className="header-button" href="/"> Home </a>
        <button className="header-button" onClick={() => logoutBtn()}> Logout </button>
        <a className="header-button" href="/cv"> CV </a>
        <a className="header-button" href="/notes"> Notes </a>
        <a className="header-button" href="/txt"> TXT </a>
      </section>
      <hr className="header-line" />
    </>
    :
    <>
      <section className="header">
        <a className="header-button" href="/"> Home </a>
        <a className="header-button" href="/login"> Login </a>
        <a className="header-button" href="/cv"> CV </a>
        <a className="header-button" href="/notes"> Notes </a>
        <a className="header-button" href="/txt"> TXT </a>
      </section>
      <hr className="header-line" />
    </>
  );
}
  
export default NavigationBar;