import React from 'react';
import { useState, useEffect } from "react";
import { BrowserRouter as Router, Route, Routes, Navigate } from "react-router-dom";
import Home from "./components/Home";
import NavigationBar from "./components/bar/NavigationBar";
import SideBar from "./components/bar/SideBar";
import Login from "./components/Login";
import Note from "./components/Note";
import TXT from "./components/TXT";
import CV from "./components/CV";
import './App.css';
import SessionContextProvider from "./contexts/SessionContext";

function App() {
  const initialLogged = {  
    loggedUser: {
      id: '',
      pwd: '',
    },
    loggedIn: false
  }
  
  const [logged, setLogged] = useState(initialLogged);

  useEffect(() => {
    const storedSetLogged = localStorage.getItem("logged");
    setLogged(JSON.parse(storedSetLogged));
  }, []);
  function persistLogged(newLogged) {
    setLogged(newLogged);
    localStorage.setItem("logged", JSON.stringify(newLogged));
  }

  return (
    <SessionContextProvider value={{logged, persistLogged}}>
      <div className="column-container">
        <Router basename={process.env.PUBLIC_URL}>
          <NavigationBar />
          <div className="row-container">
            <SideBar />
            <Routes>
              <Route exact path="/" element={<Home />} />
              <Route path="/login" element={<Login />} />
              <Route path="/cv" element={<CV />}/>
              <Route path="/notes" element={<Note />} />
              <Route path="/txt" element={<TXT />} />
              <Route path="*" element={<Navigate to="/" />} />
            </Routes>
          </div>
        </Router>
      </div>
    </SessionContextProvider>
  );
}

export default App;
