import React from 'react';
import { createContext, useContext, useState } from "react";

const SessionContext = createContext({
  loggedUser: {
    id: '',
    pwd: '',
  },
  loggedIn: false,
  setLoggedUser: () => {},
  setLoggedIn: () => {},
  setLoggedOut: () => {}
});

const SessionContextProvider = ({children}) => {
  const setLoggedUser = (data) => {setLogged(prevState => ({...prevState, loggedUser: data}))}
  const setLoggedIn = (inputs) => {
    if (inputs.id === "sagit25" && inputs.pwd === "TXT_SOOBIN") {
      setLogged(prevState => ({...prevState, loggedIn: true}));
    }
    else {
      window.alert("잘못된 접근입니당!");
    }
  }
  const setLoggedOut = () => {
    setLogged(prevState => ({...prevState, loggedIn: false}));
  }
  const initialState = {
    loggedUser: {},
    loggedIn: false,
    setLoggedUser,
    setLoggedIn,
    setLoggedOut
  }

  const [logged, setLogged] = useState(initialState);

  return (
    <SessionContext.Provider value={logged}>
      {children}
    </SessionContext.Provider>
  )
}

export default SessionContextProvider;

export const useSessionContext = () => useContext(SessionContext);
